            if rd:
                try:
                    dt = datetime.strptime(rd, '%Y-%m-%d')
                    if dt <= datetime(2026, 1, 26):
                        pred = row['my_prediction']
                        print(f\"qid={row['qid']} | res={rd} | title={row['title'][:85]}\")
                        print(f\"  pred={pred[:90] if pred else 'NONE'}\")
                        print()
                except:
                    pass
